import React from 'react';
import { Button, Modal } from '@linm-soft-org/linm-web-common-components';

export type HeaderDiscountClearConfirmModalProps = {
  isOpen: boolean;
  onStay: () => void;
  onConfirm: () => void;
  'data-testid'?: string;
};

/**
 * Xác nhận khi nhập giảm giá dòng — tắt giảm giá tổng footer (parity UnsavedChangesModal).
 */
export const HeaderDiscountClearConfirmModal: React.FC<HeaderDiscountClearConfirmModalProps> = ({
  isOpen,
  onStay,
  onConfirm,
  'data-testid': testId = 'header-discount-clear-modal',
}) => (
  <Modal
    isOpen={isOpen}
    onClose={onStay}
    title="Giảm giá theo dòng"
    size="sm"
    closeOnOverlayClick={false}
    data-testid={testId}
  >
    <p style={{ marginBottom: '20px', color: 'var(--color-text-secondary, #6b7280)' }}>
      Nhập giảm giá trên dòng hàng sẽ tắt <strong>giảm giá tổng</strong> ở footer và xóa các giá trị
      đã nhập (checkbox, số tiền, phân bổ). Bạn có chắc muốn tiếp tục?
    </p>
    <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
      <Button variant="secondary" onClick={onStay} data-testid={`${testId}-stay`}>
        Ở lại
      </Button>
      <Button variant="primary" onClick={onConfirm} data-testid={`${testId}-confirm`}>
        Tiếp tục
      </Button>
    </div>
  </Modal>
);
