import React, { useEffect, useState } from 'react';
import { Button, Modal, Select } from '@linm-soft-org/linm-web-common-components';
import type { SelectOption } from '@linm-soft-org/linm-web-common-components';
import styles from '../../styles/documentForm.module.css';

export const DEFAULT_PRINT_TEMPLATE_OPTIONS: SelectOption[] = [
  { value: '', label: '— Chọn mẫu in —' },
  { value: 'default', label: 'Mẫu in mặc định (placeholder)' },
  { value: 'a4-portrait', label: 'A4 dọc (placeholder)' },
  { value: 'a4-landscape', label: 'A4 ngang (placeholder)' },
];

export interface VoucherPrintModalProps {
  isOpen: boolean;
  onClose: () => void;
  voucherTitle?: string;
  printTemplateOptions?: SelectOption[];
  onPrint?: (templateId: string) => void | Promise<void>;
  printing?: boolean;
  testIdPrefix: string;
}

export const VoucherPrintModal: React.FC<VoucherPrintModalProps> = ({
  isOpen,
  onClose,
  voucherTitle,
  printTemplateOptions = DEFAULT_PRINT_TEMPLATE_OPTIONS,
  onPrint,
  printing = false,
  testIdPrefix,
}) => {
  const [templateId, setTemplateId] = useState('');

  useEffect(() => {
    if (isOpen) setTemplateId('');
  }, [isOpen]);

  const handlePrint = () => {
    if (!templateId) return;
    onPrint?.(templateId);
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="In chứng từ"
      size="md"
      data-testid={`${testIdPrefix}-print-modal`}
    >
      {voucherTitle && (
        <p
          style={{ marginBottom: 12, fontSize: 14, color: 'var(--color-text-secondary, #6c757d)' }}
          data-testid={`${testIdPrefix}-print-voucher-title`}
        >
          Chứng từ: <strong>{voucherTitle}</strong>
        </p>
      )}

      <div style={{ marginBottom: 16 }}>
        <label className={styles.label} htmlFor={`${testIdPrefix}-print-template`}>Mẫu in *</label>
        <Select
          id={`${testIdPrefix}-print-template`}
          data-testid={`${testIdPrefix}-print-template`}
          options={printTemplateOptions}
          value={templateId}
          onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setTemplateId(e.target.value)}
        />
      </div>

      <div className={styles.modalActions}>
        <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-print-cancel`}>
          Hủy
        </Button>
        <Button
          variant="primary"
          onClick={handlePrint}
          loading={printing}
          disabled={!templateId}
          data-testid={`${testIdPrefix}-print-confirm`}
        >
          <i className="fas fa-print" /> In
        </Button>
      </div>
    </Modal>
  );
};
