import { apiClient, unwrap } from '../api';
import type { BffResponse } from '@linm-soft-org/linm-web-common-components';
import type { CustomerDto, MaterialDto, PagedResult } from './models';

const MASTER = '/master';

function qsFilter(params: Record<string, string | number | boolean | undefined>) {
  const q = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') q.set(k, String(v));
  });
  return q.toString();
}

export const masterEndpoint = {
  searchCustomers: async (params: {
    search?: string;
    page: number;
    pageSize: number;
    customerType?: string;
    isActive?: boolean;
  }) => {
    const qs = qsFilter({
      search: params.search,
      page: params.page,
      pageSize: params.pageSize,
      customerType: params.customerType,
      isActive: params.isActive ?? true,
    });
    const res = await apiClient.get<BffResponse<PagedResult<CustomerDto>>>(`${MASTER}/customers?${qs}`);
    return unwrap(res);
  },
  getCustomer: async (customerId: string) => {
    const res = await apiClient.get<BffResponse<CustomerDto>>(`${MASTER}/customers/${customerId}`);
    return unwrap(res);
  },
  searchMaterials: async (params: { search?: string; page: number; pageSize: number }) => {
    const qs = qsFilter({
      search: params.search,
      page: params.page,
      pageSize: params.pageSize,
      isActive: true,
    });
    const res = await apiClient.get<BffResponse<PagedResult<MaterialDto> | MaterialDto[]>>(
      `${MASTER}/materials?${qs}`,
    );
    const data = unwrap(res);
    const paged = Array.isArray(data)
      ? {
          items: data,
          totalCount: data.length,
          page: params.page,
          pageSize: params.pageSize,
        }
      : data;
    const items = paged?.items ?? [];
    const totalCount = Number(paged?.totalCount ?? items.length);
    const totalPages = Math.max(1, Math.ceil(totalCount / params.pageSize));
    return { items, page: params.page, totalPages };
  },
};
